const body = $input.first().json.body;
let payload;
if (typeof body === 'string') {
  payload = JSON.parse(decodeURIComponent(body.replace('payload=', '')));
} else if (body.payload) {
  payload = JSON.parse(body.payload);
} else {
  payload = body;
}
const action = payload.actions[0];
const parts = action.value.split('|');
// Format: action_type|cart_id|restaurant_name|restaurant_id|item_name|item_id|base_price|net_total
return [{
  json: {
    action_type: parts[0],
    cart_id: parts[1],
    restaurant_name: parts[2] || '',
    restaurant_id: parts[3] || '',
    item_name: parts[4] || '',
    item_id: parts[5] || '',
    base_price: parseFloat(parts[6]) || 0,
    net_total: parseFloat(parts[7]) || 0,
    user_id: payload.user.id,
    channel: payload.channel.id,
    message_ts: payload.message.ts
  }
}];

// Track rejection count in workflow static data
const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().split('T')[0];
if (staticData.rejectionDate !== today) {
  staticData.rejectionCount = 0;
  staticData.rejectionDate = today;
}
staticData.rejectionCount = (staticData.rejectionCount || 0) + 1;
return [{ json: { ...($input.first().json), rejection_count: staticData.rejectionCount } }];

